using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly ModelTrainingService _trainingService;

    private static readonly string[] Categories = ["Billing", "General", "Technical"];

    public TicketController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        ModelTrainingService trainingService)
    {
        _predictionPool = predictionPool;
        _trainingService = trainingService;
    }

    /// <summary>Predict the category for a support ticket.</summary>
    [HttpPost("predict")]
    public ActionResult<TicketPredictionResponse> Predict([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < Categories.Length && i < prediction.Score.Length; i++)
            confidence[Categories[i]] = prediction.Score[i];

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }

    /// <summary>Retrain the model and return evaluation metrics.</summary>
    [HttpPost("train")]
    public ActionResult<string> Train()
    {
        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");

        var report = _trainingService.TrainAndSave(dataPath, modelPath);
        return Ok(report);
    }
}

