private readonly string[] _labelNames;

public TicketController(
    PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
    ModelTrainingService trainingService)
{
    _predictionPool = predictionPool;
    _trainingService = trainingService;

    // Extract label ordering from the model's output schema so confidence
    // scores map to the correct category names.
    var engine = predictionPool.GetPredictionEngine();
    var scoreColumn = engine.OutputSchema.GetColumnOrNull("Score");
    if (scoreColumn.HasValue)
    {
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.Value.GetSlotNames(ref slotNames);
        _labelNames = slotNames.DenseValues()
            .Select(v => v.ToString()).ToArray();
    }
    else
    {
        _labelNames = ["Billing", "General", "Technical"];
    }
}

